const ctx=$json.ctx;
const rules='You are tnAI, the weekly analyst for the Managing Director of Tecknuovo (a UK digital-delivery consultancy). You have analysed every client call, weekly delivery report and the CRM for the past 7 days. Write HER weekly brief. Rules: she thinks ZOOMED OUT - never mention routine day-to-day delivery detail; roll things up into patterns. Only genuinely MD-level items go in needs_you: critical risks, account/relationship risks, risks sitting unresolved for 2+ weeks (call these out with their age - the system does not forget), or commercial moves worth her weight. If nothing needs her, say so plainly - that is a good week. Mention early warnings: the same risk theme recurring on one account, opportunity chatter accelerating, an account going quiet. Be concrete: name accounts and amounts. Plain UK business English, no jargon, no flattery. Never use em dashes; use commas or hyphens. Return ONLY JSON: {"whats_happening":"3-4 sentences","why":"2-3 sentences on the pattern behind the week","needs_you":["max 3 short items, or an empty array if nothing genuinely needs her"]}';
const prompt=rules+'\n\nTHIS WEEK\'S DATA:\n'+JSON.stringify(ctx);
return [{json:{prompt}}];

const raw=($json.text||$json.response||$json.output||'').trim();
const m=raw.match(/\{[\s\S]*\}/); if(!m){return [];}
let obj; try{obj=JSON.parse(m[0]);}catch(e){return [];}
const out={
 whats_happening:String(obj.whats_happening||'').slice(0,1500),
 why:String(obj.why||'').slice(0,1200),
 needs_you:Array.isArray(obj.needs_you)?obj.needs_you.slice(0,3).map(function(x){return String(x).slice(0,300)}):[]
};
if(!out.whats_happening){return [];}
const e=function(s){return String(s).replace(/'/g,"''")};
const sql="INSERT INTO briefs (audience,period_start,period_end,content) VALUES ('leadership', now()::date-7, now()::date, '"+e(JSON.stringify(out))+"'::jsonb);";
return [{json:{sql,preview:out}}];
